package main

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
)

// GenerateRSAKeyPair generates an RSA key pair and saves them to files.
// It takes the paths for the public key and private key as parameters.
// It returns an error if the key generation or file operations fail.
func GenerateRSAKeyPair(publicKeyPath, privateKeyPath string) error {
	// Generate a new RSA private key
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		return fmt.Errorf("failed to generate RSA private key: %w", err)
	}

	// Create a new public key from the private key
	publicKey := &privateKey.PublicKey

	// Encode the private key to PEM format
	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	})

	// Write the private key to the file
	err = os.WriteFile(privateKeyPath, privateKeyPEM, 0600)
	if err != nil {
		return fmt.Errorf("failed to write private key to file: %w", err)
	}

	// Encode the public key to PEM format
	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: x509.MarshalPKCS1PublicKey(publicKey),
	})

	// Write the public key to the file
	err = os.WriteFile(publicKeyPath, publicKeyPEM, 0644)
	if err != nil {
		return fmt.Errorf("failed to write public key to file: %w", err)
	}

	return nil
}

func main() {
	publicKeyPath := "path/to/public_key.pem"
	privateKeyPath := "path/to/private_key.pem"

	err := GenerateRSAKeyPair(publicKeyPath, privateKeyPath)
	if err != nil {
		fmt.Println("Error generating RSA key pair:", err)
	}
}
```

