def parse(path, require_exists=True, require_parses=True):
    if not os.path.isfile(path):
        if require_exists:
            raise ConfigError('not found: ' + path)
        else:
            return None
    try:
        with open(path) as f:
            return yaml.safe_load(f)
    except Exception, error:
        if require_parses:
            raise ConfigError('parse error: ' + path)

