def validate_feature_tags(feature_name, tags, tag_registry):
    # Check for duplicate tags within the same feature
    if len(tags) != len(set(tags)):
        raise ValueError(f"Duplicate tags found in feature '{feature_name}'.")

    # Initialize a set to track used tags
    used_tags = set()

    # Check each tag against the tag registry and criteria
    for tag in tags:
        # Check if the tag is in the tag registry
        if tag not in tag_registry:
            raise ValueError(f"Tag '{tag}' is not in the tag registry.")

        # Check if the tag is a version tag
        if tag.startswith('v'):
            # Ensure version tags are correctly formatted
            if not tag[1:].isdigit():
                raise ValueError(f"Version tag '{tag}' is not correctly formatted.")

        # Check if the tag is a bugzilla tag
        if tag.startswith('bz'):
            # Ensure bugzilla tags are correctly formatted
            if not tag[2:].isdigit():
                raise ValueError(f"Bugzilla tag '{tag}' is not correctly formatted.")

        # Ensure the tag is unique within the feature
        if tag in used_tags:
            raise ValueError(f"Tag '{tag}' is used more than once in feature '{feature_name}'.")

        # Add the tag to the set of used tags
        used_tags.add(tag)

    # Check for required tags
    required_tags = ['required_tag1', 'required_tag2']  # Example required tags
    for tag in required_tags:
        if tag not in tags:
            raise ValueError(f"Required tag '{tag}' is missing in feature '{feature_name}'.")

    return True
