  def initialize(*files)
    @config = {}
    default_config = YAML.load_file('default_config.yml') rescue {}
    @config.merge!(default_config)

    files.each do |file|
      begin
        path = Pathname.new(file)
        if path.exist? && path.extname == '.yml'
          config = YAML.load_file(file) rescue {}
          @config.merge!(config)
        else
          puts "Warning: File '#{file}' does not exist or is not a YAML file."
        end
      rescue => e
        puts "Error loading file '#{file}': #{e.message}"
      end
    end

    @data_dir = @config['data_dir'] || 'data'
    @log_dir = @config['log_dir'] || 'logs'
  end
end
