// CompileAndRun takes an io.Reader containing the source code of a program,
// compiles it, runs it, and returns the output as a string. It also measures
// the time taken for compilation and execution and logs the metrics.
func CompileAndRun(src io.Reader) (string, error) {
	var stdout bytes.Buffer
	var stderr bytes.Buffer
	startTime := time.Now()

	// Compile the program
	cmd := exec.Command("go", "build", "-o", "temp", "-")
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	err := cmd.Run()
	if err != nil {
		return "", fmt.Errorf("failed to compile: %v, stderr: %s", err, stderr.String())
	}

	// Run the compiled program
	cmd = exec.Command("./temp")
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr
	err = cmd.Run()
	if err != nil {
		return "", fmt.Errorf("failed to run: %v, stderr: %s", err, stderr.String())
	}

	// Measure and log metrics
	elapsed := time.Since(startTime)
	log.Printf("Compilation and execution took %v", elapsed)

	return stdout.String(), nil
}
