// HandleWebhookCallback handles webhook callbacks for user follow events and challenge verification.
func HandleWebhookCallback(w http.ResponseWriter, r *http.Request) {
	// Parse JSON data from the request body
	var data map[string]interface{}
	if err := json.NewDecoder(r.Body).Decode(&data); err != nil {
		http.Error(w, "Invalid JSON", http.StatusBadRequest)
		return
	}

	// Check if the event type is "follow"
	if eventType, ok := data["event"].(string); ok && eventType == "follow" {
		// Extract the username from the event data
		username, ok := data["payload"].(map[string]interface{})["username"].(string)
		if !ok {
			http.Error(w, "Invalid event payload", http.StatusInternalServerError)
			return
		}
		fmt.Println("User followed:", username)
	} else if eventType, ok := data["event"].(string); ok && eventType == "challenge" {
		// Extract the challenge token from the event data
		challengeToken, ok := data["challenge"].(string)
		if !ok {
			http.Error(w, "Invalid event payload", http.StatusInternalServerError)
			return
		}
		// Respond with a 200 status code and the challenge token
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(challengeToken))
	} else {
		http.Error(w, "Unsupported event type", http.StatusBadRequest)
	}
}
