package main

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
)

// Playlist represents a collection of tracks.
type Playlist struct {
	ID      string
	Tracks  []string
	Unique  bool
}

// AddTrackToPlaylist adds a track ID to a playlist and returns the playlist ID.
// It returns an error if the track ID is already in the playlist or if there are other issues.
func AddTrackToPlaylist(playlistID string, trackID string) (string, error) {
	// Assume playlistData is a map of playlist IDs to their corresponding Playlist structs
	playlistData := make(map[string]Playlist)

	// Check if the playlist exists
	playlist, ok := playlistData[playlistID]
	if !ok {
		return "", errors.New("playlist not found")
	}

	// Check if the track ID already exists in the playlist
	for _, existingTrack := range playlist.Tracks {
		if existingTrack == trackID {
			return "", errors.New("track already exists in playlist")
		}
	}

	// Add the track ID to the playlist
	playlist.Tracks = append(playlist.Tracks, trackID)

	// Update the playlist data with the new playlist
	playlistData[playlistID] = playlist

	// Return the playlist ID as a JSON response
	response := map[string]string{"playlist_id": playlistID}
	return json.Marshal(response)
}

// handleAddTrack is a middleware that adds a track to a playlist and returns the playlist ID.
func handleAddTrack(w http.ResponseWriter, r *http.Request) {
	// Parse the request body to get the playlist ID and track ID
	var data struct {
		PlaylistID string `json:"playlist_id"`
		TrackID    string `json:"track_id"`
	}

	if err := json.NewDecoder(r.Body).Decode(&data); err != nil {
		http.Error(w, "Invalid request body", http.StatusBadRequest)
		return
	}

	// Call the AddTrackToPlaylist function
	playlistID, err := AddTrackToPlaylist(data.PlaylistID, data.TrackID)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	// Write the playlist ID as a JSON response
	w.Header().Set("Content-Type", "application/json")
	if err := json.NewEncoder(w).Encode(map[string]string{"playlist_id": playlistID}); err != nil {
		http.Error(w, "Failed to encode response", http.StatusInternalServerError)
		return
	}
}

func main() {
	http.HandleFunc("/add_track", handleAddTrack)
	fmt.Println("Server started on port 8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Println("Error starting server:", err)
	}
}
