package main

import (
	"fmt"
	"net/http"
	"net/url"
)

// ServeLandingPageOrRedirect handles requests for landing pages or redirects.
// It checks if the path contains a valid URL-encoded identifier. If so, it redirects
// to the original URL. If the identifier is invalid or the URL is malformed, it returns
// a 404 Not Found error.
func ServeLandingPageOrRedirect(w http.ResponseWriter, r *http.Request) {
	// Extract the path from the request
	path := r.URL.Path

	// Decode the path to extract the identifier
	identifier, err := url.PathUnescape(path)
	if err != nil {
		http.Error(w, "Invalid path", http.StatusNotFound)
		return
	}

	// Construct the original URL using the identifier
	originalURL := fmt.Sprintf("http://example.com/%s", identifier)

	// Check if the original URL is valid
	if _, err := url.ParseRequestURI(originalURL); err != nil {
		http.Error(w, "Invalid URL", http.StatusNotFound)
		return
	}

	// Redirect to the original URL
	http.Redirect(w, r, originalURL, http.StatusFound)
}

func main() {
	http.HandleFunc("/", ServeLandingPageOrRedirect)
	fmt.Println("Server is running on port 8080...")
	http.ListenAndServe(":8080", nil)
}
