function handleFormSubmit(event) {
    event.preventDefault(); // Prevent the default form submission behavior

    // Retrieve form data
    const formData = new FormData(event.target);

    // Initialize an array to store valid input values
    const validInputs = [];

    // Iterate over form data
    formData.forEach((value, key) => {
        // Trim the value and check if it's not empty
        const trimmedValue = value.trim();
        if (trimmedValue) {
            validInputs.push({ key, value: trimmedValue });
        }
    });

    // Store valid input values in local storage
    localStorage.setItem('formInputs', JSON.stringify(validInputs));

    // Reload the page
    location.reload();
}
