  // Select the HTML element with the id "searchHeading"
  var headingElement = document.getElementById("searchHeading");

  // Check if the query is empty
  if (query === "") {
    // Set the text to "No search results found."
    headingElement.textContent = "No search results found.";
  } else {
    // Set the text to "Search results for: [query]"
    headingElement.textContent = "Search results for: " + query;
  }
}
