```javascript
function refreshCustomMultiSelect(multiSelectElement, searchEnabled, groupingEnabled) {
  // Retrieve the current options from the multi-select element
  const currentOptions = multiSelectElement.options;
  const filteredOptions = [];

  // If search is enabled, filter options based on user input
  if (searchEnabled) {
    const userInput = document.getElementById('searchInput').value.toLowerCase();
    for (let i = 0; i < currentOptions.length; i++) {
      const optionText = currentOptions[i].text.toLowerCase();
      if (optionText.includes(userInput)) {
        filteredOptions.push(currentOptions[i]);
      }
    }
  } else {
    filteredOptions = currentOptions;
  }

  // If grouping is enabled, organize options into groups
  if (groupingEnabled) {
    const groupProperty = 'group'; // Assuming 'group' is a property in the options
    const groupedOptions = {};

    for (let i = 0; i < filteredOptions.length; i++) {
      const group = filteredOptions[i][groupProperty];
      if (!groupedOptions[group]) {
        groupedOptions[group] = [];
      }
      groupedOptions[group].push(filteredOptions[i]);
    }

    // Clear existing options in the multi-select element
    while (multiSelectElement.firstChild) {
      multiSelectElement.removeChild(multiSelectElement.firstChild);
    }

    // Add grouped options to the multi-select element
    for (const group in groupedOptions) {
      const groupElement = document.createElement('optgroup');
      groupElement.label = group;
      for (let i = 0; i < groupedOptions[group].length; i++) {
        const option = document.createElement('option');
        option.value = groupedOptions[group][i].value;
        option.text = groupedOptions[group][i].text;
        groupElement.appendChild(option);
      }
      multiSelectElement.appendChild(groupElement);
    }
  } else {
    // Clear existing options in the multi-select element
    while (multiSelectElement.firstChild) {
      multiSelectElement.removeChild(multiSelectElement.firstChild);
    }

    // Add filtered options to the multi-select element
    for (let i = 0; i < filteredOptions.length; i++) {
      const option = document.createElement('option');
      option.value = filteredOptions[i].value;
      option.text = filteredOptions[i].text;
      multiSelectElement.appendChild(option);
    }
  }
}
```

