        // modal other than deleting
        function disableTabModalShown() {

            $('.modal').on('shown.bs.modal', function() {

                var modal = $(this),
                focusableChildren = modal.find('a[href], a[data-dismiss], area[href], input, select, textarea, button, iframe, object, embed, *[tabindex], *[contenteditable]'),
                numElements = focusableChildren.length,
                currentIndex = 0,
                focus,
                focusPrevious,
                focusNext;

                $(document.activeElement).blur();

                focus = function() {
                    var focusableElement = focusableChildren[currentIndex];
                    if (focusableElement) {
                        focusableElement.focus();
                    }
                };

                focusPrevious = function () {
                    currentIndex--;
                    if (currentIndex < 0) {
                        currentIndex = numElements - 1;
                    }

                    focus();

                    return false;
                };

                focusNext = function () {
                    currentIndex++;
                    if (currentIndex >= numElements) {
                        currentIndex = 0;
                    }

                    focus();

                    return false;
                };

                $(document).on('keydown', function (e) {

                    if (e.keyCode === 9 && e.shiftKey) {
                        e.preventDefault();
                        focusPrevious();
                    }
                    else if (e.keyCode === 9) {
                        e.preventDefault();
                        focusNext();
                    }
                });

                $(this).focus();
            });

            $('.modal').on('hidden.bs.modal', function() {
                $(document).unbind('keydown');
            });
        }


        $('#prompt-modal').off('hidden.bs.modal');
        $('#prompt-modal').modal({
            backdrop: 'local_backdrop',
            keyboard: true,
            show: true
        });
        disableTabModalShown();

    };
}

