function slideAndHideMessage(message, duration) {
    // Create a new div element to hold the message
    const messageDiv = document.createElement('div');
    messageDiv.textContent = message;
    messageDiv.style.position = 'absolute';
    messageDiv.style.top = '50%';
    messageDiv.style.left = '-100%';
    messageDiv.style.transform = 'translateX(100%)';
    messageDiv.style.width = '200px';
    messageDiv.style.height = '50px';
    messageDiv.style.backgroundColor = '#f0f0f0';
    messageDiv.style.border = '1px solid #ccc';
    messageDiv.style.padding = '10px';
    messageDiv.style.boxSizing = 'border-box';
    messageDiv.style.transition = `transform ${duration / 1000}s ease-in-out`;

    // Append the messageDiv to the body
    document.body.appendChild(messageDiv);

    // Slide the messageDiv in from the left
    messageDiv.style.transform = 'translateX(0%)';

    // Hide the messageDiv after the specified duration
    setTimeout(() => {
        messageDiv.style.transform = 'translateX(-100%)';
        setTimeout(() => {
            document.body.removeChild(messageDiv);
        }, duration);
    }, duration);
}
