  // Helper function to handle row click
  function handleRowClick(row) {
    // Check if the row is already selected
    if (row === selectedRow) {
      // If selected, unselect it and reset group
      unselectRow(row);
      selectedGroup = null;
    } else {
      // If not selected, select it and reset group
      selectRow(row);
      selectedGroup = getRowGroup(row);
    }
  }

  // Helper function to handle checkbox change
  function handleCheckboxChange(checkbox) {
    // Get the row associated with the checkbox
    const row = checkbox.closest('.table-row');
    // Toggle the checkbox
    checkbox.checked = !checkbox.checked;

    // If the checkbox is checked, select the row
    if (checkbox.checked) {
      selectRow(row);
      selectedGroup = getRowGroup(row);
    } else {
      // If the checkbox is unchecked, unselect the row
      unselectRow(row);
    }
  }

  // Helper function to select a row
  function selectRow(row) {
    // Check if the row is already selected
    if (row === selectedRow) return;
    // Unselect the previously selected row if any
    if (selectedRow) unselectRow(selectedRow);
    // Select the current row
    row.classList.add('selected');
    // Update the selected row variable
    selectedRow = row;
  }

  // Helper function to unselect a row
  function unselectRow(row) {
    // Remove the selected class from the row
    row.classList.remove('selected');
    // Update the selected row variable
    selectedRow = null;
  }

  // Helper function to get the row group
  function getRowGroup(row) {
    // Assuming the row group is defined by a specific class or attribute
    const groupClass = row.getAttribute('data-group');
    return groupClass;
  }
}
