from flask import Flask, request, jsonify

app = Flask(__name__)

# Dictionary to store variables
variables = {}

@app.route('/variable', methods=['GET', 'POST'])
def manage_variable():
    # Get the variable name from the request
    name = request.args.get('name')

    if not name:
        return jsonify({"error": "Variable name is required"}), 400

    if request.method == 'GET':
        # Get the variable value
        if name in variables:
            return jsonify({"value": variables[name]}), 200
        else:
            return jsonify({"error": "Variable not found"}), 404

    elif request.method == 'POST':
        # Set the variable value
        value = request.args.get('value')
        if value:
            variables[name] = value
            return jsonify({"message": "Variable set successfully"}), 200
        else:
            return jsonify({"error": "Value is required"}), 400

    elif request.method == 'DELETE':
        # Delete the variable
        if name in variables:
            del variables[name]
            return jsonify({"message": "Variable deleted successfully"}), 200
        else:
            return jsonify({"error": "Variable not found"}), 404

if __name__ == '__main__':
    app.run(debug=True)
```

