from flask import Flask, request, render_template, redirect, url_for, flash
from flask_sqlalchemy import SQLAlchemy
from flask_login import LoginManager, UserMixin, login_user, login_required, logout_user, current_user
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///variables.db'
db = SQLAlchemy(app)
login_manager = LoginManager(app)
login_manager.login_view = 'login'

class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password_hash = db.Column(db.String(128), nullable=False)

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

class Variable(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(120), nullable=False)
    value = db.Column(db.String(255), nullable=False)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    user = db.relationship('User', backref=db.backref('variables', lazy=True))

    def __repr__(self):
        return f'<Variable {self.name}>'

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        user = User.query.filter_by(username=username).first()
        if user and user.check_password(password):
            login_user(user)
            flash('Logged in successfully!', 'success')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password!', 'danger')
    return render_template('login.html')

@app.route('/logout')
@login_required
def logout():
    logout_user()
    flash('Logged out successfully!', 'success')
    return redirect(url_for('login'))

@app.route('/dashboard', methods=['GET', 'POST'])
@login_required
def dashboard():
    if request.method == 'POST':
        name = request.form['name']
        value = request.form['value']
        new_variable = Variable(name=name, value=value, user=current_user)
        db.session.add(new_variable)
        db.session.commit()
        flash('Variable created successfully!', 'success')
    variables = Variable.query.filter_by(user=current_user).all()
    return render_template('dashboard.html', variables=variables)

@app.route('/variable/<int:variable_id>', methods=['GET', 'POST'])
@login_required
def variable(variable_id):
    variable = Variable.query.get_or_404(variable_id)
    if variable.user != current_user:
        flash('You do not have permission to view this variable!', 'danger')
        return redirect(url_for('dashboard'))
    if request.method == 'POST':
        variable.value = request.form['value']
        db.session.commit()
        flash('Variable updated successfully!', 'success')
    return render_template('variable.html', variable=variable)

@app.route('/delete/<int:variable_id>', methods=['POST'])
@login_required
def delete(variable_id):
    variable = Variable.query.get_or_404(variable_id)
    if variable.user != current_user:
        flash('You do not have permission to delete this variable!', 'danger')
        return redirect(url_for('dashboard'))
    db.session.delete(variable)
    db.session.commit()
    flash('Variable deleted successfully!', 'success')
    return redirect(url_for('dashboard'))

