from functools import wraps
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

def check_auth(username, password):
    """This function is called to check if a username / password combination is valid."""
    return username == 'admin' and password == 'secret'

def authenticate():
    """Sends a 401 response that enables basic auth."""
    return jsonify({'error': 'Unauthorized'}), 401

def requires_auth(f):
    """Decorator to require basic auth."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.authorization
        if not auth or not check_auth(auth.username, auth.password):
            return authenticate()
        return f(*args, **kwargs)
    return decorated

@app.route('/set_preference', methods=['POST'])
@requires_auth
def set_preference():
    user_id = request.json.get('user_id', None)
    key = request.json.get('key', None)
    value = request.json.get('value', None)

    if not isinstance(user_id, str) or not isinstance(key, str) or not isinstance(value, str):
        raise ValueError("Both user_id, key, and value must be strings.")

    user_preferences = request.json.get('user_preferences', {})
    user_preferences[user_id] = user_preferences.get(user_id, {})
    user_preferences[user_id][key] = value

    return jsonify(user_preferences)

if __name__ == '__main__':
