function executeBinary(binary, args, expectedError) {
  return new Promise((resolve, reject) => {
    const child = spawn(binary, args);

    let errorOutput = '';

    child.stderr.on('data', (data) => {
      errorOutput += data.toString();
    });

    child.on('close', (code) => {
      if (code !== 0) {
        if (errorOutput.includes(expectedError)) {
          resolve();
        } else {
          reject(new Error(`Expected error output to contain "${expectedError}", but got "${errorOutput}"`));
        }
      } else {
        reject(new Error(`Binary exited with code ${code}, but expected non-zero`));
      }
    });
  });
}
